Send Prompt.code:
// Send a prompt to Gemini.
// The text reply is written to state.data.
prompt(
  // 1) The prompt text. Reference upstream state with $.
  `Summarize this text: ${JSON.stringify($.data)}`,
  {
    // 2) Gemini model id (see https://ai.google.dev/gemini-api/docs/models).
    model: 'gemini-2.5-flash',
    // 3) Optional generation tuning.
    temperature: 0.7,
  }
);
